dataset = koi_koi_raw
| filter source_log_type = "Alerts"
| alter device_id = coalesce(
    device_id,
    if(json_extract_scalar(resources, "$[0].type") = "device", json_extract_scalar(resources, "$[0].data.id"), null),
    if(json_extract_scalar(resources, "$[1].type") = "device", json_extract_scalar(resources, "$[1].data.id"), null),
    if(json_extract_scalar(resources, "$[2].type") = "device", json_extract_scalar(resources, "$[2].data.id"), null))
| filter device_id != null
| comp count_distinct(device_id) as devices
| view graph type = single subtype = standard yaxis = devices scale_threshold("#0054f5") dataunit = "Devices"

