| alter finding_severity = json_extract_scalar(findings_arr, "$.severity")
| filter finding_severity in ("critical", "high")
| comp count_distinct(item_id_res) as high_risk_items
| view graph type = single yaxis = high_risk_items scale_threshold("#ff0082") dataunit = "Items"

