        finding_severity = json_extract_scalar(findings_arr, "$.severity")
| filter finding_severity != null and item_risk_level != null
| alter koi_finding_key = concat(koi_notif, "|", finding_name)
| comp count_distinct(koi_finding_key) as findings by item_risk_level, finding_severity
| sort desc findings
| view graph type = column subtype = stacked header = "Finding Severity by Item Risk Level (extension items only)" xaxis = item_risk_level yaxis = findings series = finding_severity

dataset = koi_koi_raw
| filter source_log_type = "Alerts"
| alter koi_notif = json_extract_scalar(metadata, "$.notification_event_id")
| alter risk_score = to_number(coalesce(
    if(json_extract_scalar(resources, "$[0].type") = "item", json_extract_scalar(resources, "$[0].data.risk"), null),
    if(json_extract_scalar(resources, "$[1].type") = "item", json_extract_scalar(resources, "$[1].data.risk"), null),
    if(json_extract_scalar(resources, "$[2].type") = "item", json_extract_scalar(resources, "$[2].data.risk"), null))),
        item_id_res = coalesce(
    if(json_extract_scalar(resources, "$[0].type") = "item", json_extract_scalar(resources, "$[0].data.item_id"), null),
    if(json_extract_scalar(resources, "$[1].type") = "item", json_extract_scalar(resources, "$[1].data.item_id"), null),
    if(json_extract_scalar(resources, "$[2].type") = "item", json_extract_scalar(resources, "$[2].data.item_id"), null))
| filter risk_score != null
| alter risk_band = if(risk_score < 2, "0-2", risk_score < 4, "2-4", risk_score < 6, "4-6", risk_score < 8, "6-8", "8-10")
| comp count_distinct(item_id_res) as items by risk_band
| sort asc risk_band
| view graph type = column header = "Risk Score Distribution (distinct extension items)" xaxis = risk_band yaxis = items

