dataset = koi_koi_raw
| filter source_log_type = "Alerts"
| alter first_seen = coalesce(
    if(json_extract_scalar(resources, "$[0].type") = "item_instance", json_extract_scalar(resources, "$[0].data.first_seen"), null),
    if(json_extract_scalar(resources, "$[1].type") = "item_instance", json_extract_scalar(resources, "$[1].data.first_seen"), null),
    if(json_extract_scalar(resources, "$[2].type") = "item_instance", json_extract_scalar(resources, "$[2].data.first_seen"), null)),
        item_id = coalesce(
    item_id,
    if(json_extract_scalar(resources, "$[0].type") = "item_instance", json_extract_scalar(resources, "$[0].data.item_id"), null),
